  const query = new URLSearchParams()

  const nest = (name: string, _value: unknown) => {
    const value = _value instanceof Set ? Array.from(_value) : _value
    if (Array.isArray(value)) {
      if (value.length) {
        for (const index in value) {
          nest(`${name}[${index}]`, value[index])
