    } else if (typeof value === 'object' && value !== null) {
      for (const [key, obj] of Object.entries(value)) {
        nest(`${name}[${key}]`, obj)
      }
    } else {
      query.append(name, value as string)
    }
  }

  for (const [key, value] of Object.entries(data)) {
    nest(key, value)
  }

  return query.toString()
